"""Rendering helpers for simplified managed instruction files."""

from __future__ import annotations

from pathlib import Path

from agent_workbench.manifest import AgentAssetsManifest


MANAGED_MARKERS = {
    ".md": "<!-- generated by agent-workbench: do not edit directly -->\n",
    ".yaml": "# generated by agent-workbench: do not edit directly\n",
    ".yml": "# generated by agent-workbench: do not edit directly\n",
    ".py": "# generated by agent-workbench: do not edit directly\n",
    ".ps1": "# generated by agent-workbench: do not edit directly\n",
    ".sh": "# generated by agent-workbench: do not edit directly\n",
}


def managed_text(path: Path, body: str) -> str:
    """Prefix generated content with a managed-file marker."""
    marker = MANAGED_MARKERS.get(path.suffix, "# generated by agent-workbench: do not edit directly\n")
    content = body if body.endswith("\n") else body + "\n"
    return marker + content


def render_agent_entry(agent: str, manifest: AgentAssetsManifest) -> tuple[Path, str]:
    """Render the instruction entry file for a specific agent adapter."""
    normalized = agent.lower()
    if normalized == "codex":
        path = Path("AGENTS.md")
    elif normalized == "claude":
        path = Path("CLAUDE.md")
    elif normalized == "gemini":
        path = Path("GEMINI.md")
    else:
        raise ValueError(f"Unsupported agent '{agent}'")

    lines = [
        f"# {path.name}",
        "",
        "This file is rendered from `agent_assets.yaml` by agent-workbench.",
        "",
        "## Agents",
        "",
        *(f"- `{name}`" for name in manifest.agents),
        "",
        "## Skills",
        "",
        *(f"- `{skill.name}` ({skill.scope}/{skill.mode})" for skill in manifest.skills),
        "",
        "## Commands",
        "",
        "- `bootstrap apply` installs project/global assets",
        "- `bootstrap verify` runs smoke checks",
        "- `bootstrap pull` refreshes from your personal tool repo",
        "- `bootstrap push --skill <name>` sends named skill edits back to the tool repo",
    ]
    return path, managed_text(path, "\n".join(lines))
